### Steps to reproduce

1. Create a `TextField` with `onTapOutside` defined and `DropDownMenu` with `onSelected` and `requestFocusOnTap` set to false. 
2. Tap into the `TextField`. 
3. Tap on the `DropDownMenu` label
    - `onTapOutside` is not triggered, The menu is opened.
4. Tap on a menu item
    - `onTapOutside` is triggered, but `onSelected` is not. Menu is not hidden.

### Expected results

- Tapping on the `DropDown` menu label should trigger `TextField.onTapOutside`
- Tapping on a menu item should trigger both`TextField.onTapOutside` and `DropDownMenu.onSelected` sand the menu should hide.

### Actual results

- Tapping on the `DropDown` menu label does not trigger `TextField.onTapOutside`
- Tapping on a menu item should triggers only both`TextField.onTapOutside` and the menu should remains opened

### Code sample

<details><summary>Code sample</summary>

```dartimport 'package:flutter/material.dart';

void main() {
  runApp(const DropdownMenuExample());
}

class DropdownMenuExample extends StatefulWidget {
  const DropdownMenuExample({super.key});

  @override
  State<DropdownMenuExample> createState() => _DropdownMenuExampleState();
}

class _DropdownMenuExampleState extends State<DropdownMenuExample> {
  final TextEditingController colorController = TextEditingController();
  ColorLabel? selectedColor;

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: Scaffold(
        body: SafeArea(
          child: Column(
            children: <Widget>[
              SizedBox(
                width: 200,
                height: 100,
                child: TextField(
                  onTapOutside: (_) => setState(() {
                    debugPrint('TextField::onTapOutside');
                  }),
                ),
              ),
              DropdownMenu<ColorLabel>(
                controller: colorController,
                requestFocusOnTap: false,
                label: const Text('Color'),
                onSelected: (ColorLabel? color) {
                  setState(() {
                    selectedColor = color;
                  });
                },
                dropdownMenuEntries: ColorLabel.values.map((ColorLabel color) {
                  return DropdownMenuEntry<ColorLabel>(
                    value: color,
                    label: color.label,
                  );
                }).toList(),
              ),
              SizedBox(height: 200),
              Text("Selected color: $selectedColor")
            ],
          ),
        ),
      ),
    );
  }
}

enum ColorLabel {
  blue('Blue'),
  green('Green');

  const ColorLabel(this.label);
  final String label;
}

```

</details>


